xpath.script:
//
(function () {
    "use strict";

    // Error keywords that may appear in the price badge
    // when the OSRM rate calculation fails. Match
    // case-insensitively against the badge text.
    var ERROR_KEYWORDS = [
        "pilih untuk menghitung",  // placeholder text
        "error",
        "gagal",
        "tidak tersedia",
        "tidak dapat",
        "no rate",
        "unavailable"
    ];

    // Indonesian Rupiah pattern so we can detect when a
    // real price has been calculated.
    var PRICE_PATTERN = /Rp\s?\d|\d{3,}\s?(?:rb|ribu|jt|juta)?/i;

    function getSelectedRadio() {
        return document.querySelector(
            'input[name="delivery_type"]:checked'
        );
    }

    function getSelectedPriceBadge(radio) {
        if (!radio) return null;
        var li = radio.closest('li.o_delivery_carrier_select');
        if (!li) return null;
        return li.querySelector('.o_wsale_delivery_badge_price');
    }

    function isPickupSelected(radio) {
        return radio && radio.dataset &&
               radio.dataset.isPickup === '1';
    }

    function isDistanceCarrier(radio) {
        return radio && radio.getAttribute('delivery_type') === 'osrm_distance';
    }

    function priceBadgeHasError(badge) {
        if (!badge) return true;
        var text = (badge.textContent || '').trim().toLowerCase();
        if (!text) return true;
        // If we already have a real price, it is NOT an error.
        if (PRICE_PATTERN.test(text)) return false;
        // Otherwise check for explicit error keywords.
        for (var i = 0; i < ERROR_KEYWORDS.length; i++) {
            if (text.indexOf(ERROR_KEYWORDS[i]) !== -1) return true;
        }
        return false;
    }

    function updateBanners() {
        var radio = getSelectedRadio();
        var banner = document.getElementById('pickup_info_banner');
        var warning = document.getElementById('wl_gps_warning');
        if (!banner || !warning) return;

        if (isPickupSelected(radio)) {
            // Pickup mode: show pickup banner, hide GPS warning.
            banner.classList.remove('d-none');
            warning.classList.add('d-none');
            return;
        }

        // Not pickup: hide pickup banner unconditionally.
        banner.classList.add('d-none');

        // Distance-based carrier: maybe show GPS warning.
        if (isDistanceCarrier(radio)) {
            var badge = getSelectedPriceBadge(radio);
            if (priceBadgeHasError(badge)) {
                warning.classList.remove('d-none');
            } else {
                warning.classList.add('d-none');
            }
        } else {
            // Some other carrier (e.g. flat rate): no warning.
            warning.classList.add('d-none');
        }
    }

    // Re-evaluate whenever any input in #delivery_method changes.
    // Use event delegation on document so it survives AJAX
    // re-renders of the inner DOM.
    function onAnyChange(evt) {
        var target = evt.target;
        if (!target) return;
        if (target.name === 'delivery_type' ||
            target.id === 'delivery_type' ||
            (target.closest && target.closest('#delivery_method'))) {
            // Defer one tick so Odoo's own handlers finish first.
            setTimeout(updateBanners, 50);
            setTimeout(updateBanners, 300);
        }
    }
    document.addEventListener('change', onAnyChange, true);
    document.addEventListener('click', onAnyChange, true);

    // Also watch the #delivery_method subtree for DOM mutations
    // (Odoo replaces parts of it after each /shop/update_carrier
    // AJAX call, which would otherwise destroy our listeners).
    function setupObserver() {
        var dm = document.getElementById('delivery_method');
        if (!dm) return false;
        var obs = new MutationObserver(function () {
            setTimeout(updateBanners, 50);
            setTimeout(updateBanners, 400);
        });
        obs.observe(dm, {
            childList: true,
            subtree: true,
            attributes: true,
            attributeFilter: ['checked', 'class', 'data-is-pickup']
        });
        return true;
    }

    // Initial run + retry until #delivery_method exists.
    function init() {
        updateBanners();
        if (!setupObserver()) {
            // DOM not ready yet; retry shortly.
            setTimeout(init, 200);
            setTimeout(init, 800);
            setTimeout(init, 1500);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
    // Late retries to catch slow AJAX renders.
    setTimeout(init, 1000);
    setTimeout(init, 2500);
    //
})();
//
